mapper.update:
UPDATE feedback
content = #{content}, images = #{images}, contact = #{contact},
WHERE id = #{id}

mapper.select:
SELECT f.*, u.nickname as user_nickname, u.avatar as user_avatar, h.nickname as handler_nickname FROM feedback f LEFT JOIN user u ON f.user_id = u.id LEFT JOIN user h ON f.handler_id = h.id
AND (f.title LIKE CONCAT('%', #{keyword}, '%') OR f.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%'))
AND f.type = #{type}
AND f.status = #{status}
ORDER BY f.status ASC, f.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM feedback f LEFT JOIN user u ON f.user_id = u.id
AND (f.title LIKE CONCAT('%', #{keyword}, '%') OR f.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%'))
AND f.type = #{type}
AND f.status = #{status}

SELECT f.*, u.nickname as user_nickname, u.avatar as user_avatar, h.nickname as handler_nickname FROM feedback f LEFT JOIN user u ON f.user_id = u.id LEFT JOIN user h ON f.handler_id = h.id WHERE (f.status = 0) OR (f.handler_id = #{handlerId})
AND (f.title LIKE CONCAT('%', #{keyword}, '%') OR f.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%'))
AND f.type = #{type}
AND f.status = #{status}
ORDER BY CASE WHEN f.status = 0 THEN 0 ELSE 1 END, f.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM feedback f LEFT JOIN user u ON f.user_id = u.id WHERE (f.status = 0) OR (f.handler_id = #{handlerId})
AND (f.title LIKE CONCAT('%', #{keyword}, '%') OR f.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%'))
AND f.type = #{type}
AND f.status = #{status}

SELECT COUNT(*)
FROM feedback
WHERE status = #{status} AND handler_id = #{handlerId}
